const parseCSVLine = (line) => {
  const values = []
  let current = ""
  let inQuotes = false

  for (let i = 0; i < line.length; i++) {
    const char = line[i]

    if (char === '"') {
      inQuotes = !inQuotes
      continue
    }

    if (char === "," && !inQuotes) {
      values.push(current.trim())
      current = ""
      continue
    }

    current += char
  }

  values.push(current.trim())
  return values
}

const parseCSV = (text) => {
  const lines = text.trim().split("\n")
  const headers = parseCSVLine(lines[0])

  return lines.slice(1).map((line) => {
    const values = parseCSVLine(line)
    return headers.reduce((row, header, index) => {
      row[header] = values[index] ?? ""
      return row
    }, {})
  })
}

const addValueRanks = (rows) => {
  const sorted = [...rows].sort(
    (a, b) => parseFloat(b["VALUE SCORE"]) - parseFloat(a["VALUE SCORE"])
  )

  let rank = 1
  sorted.forEach((row, index) => {
    if (index > 0 && row["VALUE SCORE"] !== sorted[index - 1]["VALUE SCORE"]) {
      rank = index + 1
    }
    row.VALUE_RANK = String(rank)
  })

  return rows
}

const isTiedRank = (rows, columnKey, rankValue) => {
  const rank = parseInt(rankValue, 10)
  return rows.filter((row) => parseInt(row[columnKey], 10) === rank).length > 1
}

const formatRankLabel = (rows, columnKey, rankValue) => {
  return isTiedRank(rows, columnKey, rankValue) ? `=${rankValue}` : rankValue
}

const getPillClass = (rankValue) => {
  const rank = parseInt(rankValue, 10)

  if (rank <= 9) {
    return "rank-pill--top"
  }

  if (rank >= 26) {
    return "rank-pill--low"
  }

  return "rank-pill--mid"
}

const parsePriceValue = (value) => parseFloat(String(value).replace(/[£,]/g, ""))

const formatPriceDisplay = (value) => {
  const text = String(value).trim()
  if (text.startsWith("£")) {
    return text
  }

  return `£${parsePriceValue(text).toFixed(2)}`
}

const formatCellDisplay = (row, column, allRows) => {
  const value = row[column.key]

  if (column.display === "value-score") {
    return parseFloat(value).toFixed(3)
  }

  if (column.display === "price") {
    return formatPriceDisplay(value)
  }

  if (column.display === "raw") {
    return value
  }

  return formatRankLabel(allRows, column.key, value)
}

const getColumnConfig = (key) => TABLE_COLUMNS.find((column) => column.key === key)

const getCellPillClass = (row, column) => {
  const rankKey = column.rankKey || column.key
  return getPillClass(row[rankKey])
}

const sortRows = (rows, key, direction = "asc") => {
  const sorted = [...rows]
  const multiplier = direction === "asc" ? 1 : -1
  const column = getColumnConfig(key)

  if (key === "CITY") {
    sorted.sort((a, b) => multiplier * a.CITY.localeCompare(b.CITY))
    return sorted
  }

  if (column?.sort === "float") {
    sorted.sort((a, b) => multiplier * (parseFloat(a[key]) - parseFloat(b[key])))
    return sorted
  }

  if (column?.sort === "price") {
    sorted.sort((a, b) => multiplier * (parsePriceValue(a[key]) - parsePriceValue(b[key])))
    return sorted
  }

  sorted.sort((a, b) => multiplier * (parseInt(a[key], 10) - parseInt(b[key], 10)))
  return sorted
}

class DestinationTable {
  constructor(container, rows) {
    this.container = document.querySelector(container)
    this.baseRows = addValueRanks(rows)
    this.filteredRows = sortRows([...this.baseRows], "RANKING", "asc")
    this.sortKey = "RANKING"
    this.activeSortKey = "RANKING"
    this.sortDirection = "asc"
    this.highlightedCity = null
    this.visibleCount = ROWS_PER_PAGE

    this.container.innerHTML = `
      <div class="table-wrapper">
        <table class="ranking-table">
          <thead></thead>
          <tbody></tbody>
        </table>
      </div>
      <button type="button" class="show-more-btn" id="show-more-btn">Show more</button>
    `

    this.thead = this.container.querySelector("thead")
    this.tbody = this.container.querySelector("tbody")
    this.showMoreBtn = this.container.querySelector("#show-more-btn")

    this.showMoreBtn.addEventListener("click", () => {
      if (this.visibleCount >= this.filteredRows.length) {
        this.visibleCount = ROWS_PER_PAGE
      } else {
        this.visibleCount += ROWS_PER_PAGE
      }

      this.renderBody()
      this.updateShowMoreButton()
    })

    this.thead.addEventListener("click", (event) => {
      const header = event.target.closest("th[data-column-key]")
      if (!header) {
        return
      }

      const column = TABLE_COLUMNS.find((col) => col.key === header.dataset.columnKey)
      if (!column) {
        return
      }

      if (column.key === this.sortKey) {
        this.sortDirection = this.sortDirection === "asc" ? "desc" : "asc"
      } else {
        this.sortKey = column.key
        this.activeSortKey = column.key
        this.sortDirection = "asc"
      }

      this.visibleCount = ROWS_PER_PAGE
      this.filteredRows = sortRows(
        this.getCurrentSourceRows(),
        this.sortKey,
        this.sortDirection
      )
      this.render()
    })

    this.render()
  }

  getCurrentSourceRows() {
    return this._searchTerm
      ? this.baseRows.filter((row) => {
        const city = row.CITY.toLowerCase()
        const country = row.COUNTRY.toLowerCase()
        return city.includes(this._searchTerm) || country.includes(this._searchTerm)
      })
      : [...this.baseRows]
  }

  filter(query) {
    this._searchTerm = query.trim().toLowerCase()
    this.visibleCount = ROWS_PER_PAGE
    this.filteredRows = sortRows(
      this.getCurrentSourceRows(),
      this.sortKey,
      this.sortDirection
    )
    this.render()
  }

  highlightRow(city) {
    this.highlightedCity = city
    this.render()
  }

  renderHead() {
    this.thead.innerHTML = `
      <tr class="ranking-table__head-icons">
        <th scope="col" class="ranking-table__th-city" rowspan="2"></th>
        ${TABLE_COLUMNS.map((column) => {
      const isActive = column.key === this.activeSortKey
      const activeClass = isActive ? " ranking-table__th--active" : ""
      return `
            <th scope="col" class="ranking-table__th-icon${activeClass}" data-column-key="${column.key}">
              <span class="ranking-table__icon">${HEADER_ICONS[column.icon]}</span>
            </th>
          `
    }).join("")}
      </tr>
      <tr class="ranking-table__head-labels">
        ${TABLE_COLUMNS.map((column) => {
      const isActive = column.key === this.activeSortKey
      const activeClass = isActive ? " ranking-table__th--active" : ""
      const arrowClass =
        isActive && this.sortDirection === "desc"
          ? "ranking-table__sort-arrow--desc"
          : "ranking-table__sort-arrow--asc"
      return `
            <th scope="col" class="ranking-table__th${activeClass}" data-column-key="${column.key}">
              <span class="ranking-table__label">${column.label}</span>
              ${isActive ? `<span class="ranking-table__sort-arrow ${arrowClass}" aria-hidden="true"></span>` : ""}
            </th>
          `
    }).join("")}
      </tr>
    `
  }

  renderBody() {
    if (!this.filteredRows.length) {
      this.tbody.innerHTML = `
        <tr>
          <td class="ranking-table__empty" colspan="${TABLE_COLUMNS.length + 1}">
            No destinations match your search.
          </td>
        </tr>
      `
      this.updateShowMoreButton()
      return
    }

    const visibleRows = this.filteredRows.slice(0, this.visibleCount)

    this.tbody.innerHTML = visibleRows
      .map((row) => {
        const isHighlighted = this.highlightedCity === row.CITY
        const rowClass = isHighlighted ? " ranking-table__row--highlight" : ""

        return `
          <tr class="ranking-table__row${rowClass}">
            <td>
              <span class="city-pill">${row.CITY}, <span class="city-pill__country">${row.COUNTRY}</span></span>
            </td>
            ${TABLE_COLUMNS.map((column) => {
          const label = formatCellDisplay(row, column, this.baseRows)
          const pillClass = getCellPillClass(row, column)
          return `
                <td>
                  <span class="rank-pill ${pillClass}">${label}</span>
                </td>
              `
        }).join("")}
          </tr>
        `
      })
      .join("")

    this.updateShowMoreButton()
  }

  updateShowMoreButton() {
    if (!this.showMoreBtn) {
      return
    }

    const totalRows = this.filteredRows.length
    const allVisible = this.visibleCount >= totalRows

    if (totalRows <= ROWS_PER_PAGE) {
      this.showMoreBtn.hidden = true
      return
    }

    this.showMoreBtn.hidden = false
    this.showMoreBtn.textContent = allVisible ? "Show less" : "Show more"
  }

  render() {
    this.renderHead()
    this.renderBody()
  }
}

const loadCSV = async (url) => {
  const response = await fetch(url)
  if (!response.ok) {
    throw new Error(`Could not load ${url}`)
  }
  return parseCSV(await response.text())
}

const initDestinationTable = async (container, dataUrl = "./data/data.csv") => {
  const rows = await loadCSV(dataUrl)
  return new DestinationTable(container, rows)
}

window.initDestinationTable = initDestinationTable
